patch:
--- a/counter.v
+++ b/counter.v
@@ -1,15 +1,15 @@
 module counter_4bit(
   input clk,
   input reset,
   input enable,
   output [3:0] count
 );
   reg [3:0] counter;
   always @(posedge clk) begin
     if (reset) counter <= 4'b0;
     else if (enable) counter <= counter + 1;
   end
   assign count = counter;
 endmodule

 module system;
   wire clk_sig, rst_sig, en_sig;
   wire [3:0] cnt_out;
-  counter_4bit cnt (.clk(clk_sig), .reset(rst_sig));
+  counter_4bit cnt (.clk(clk_sig), .reset(rst_sig), .enable(en_sig), .count(cnt_out));
 endmodule

